import d from"node:crypto";import p from"crypto";it("node:crypto should be the same as crypto",()=>{expect(d).toStrictEqual(p)});var{createHash:s,createHmac:c,randomBytes:h,randomInt:l,randomUUID:y,randomFillSync:u,randomFill:i,getRandomValues:o,webcrypto:r}=d;describe("crypto object/module",()=>{it("should have a createHash()",()=>{expect(crypto.createHash).toBeDefined(),expect(s).toBeDefined()}),it("should have a createHmac()",()=>{expect(globalThis.crypto.createHmac).toBeDefined(),expect(c).toBeDefined()}),it("should have a randomBytes()",()=>{expect(globalThis.crypto.randomBytes).toBeDefined(),expect(h).toBeDefined()}),it("should have a randomInt()",()=>{expect(globalThis.crypto.randomInt).toBeDefined(),expect(l).toBeDefined()}),it("should have a randomUUID()",()=>{expect(globalThis.crypto.randomUUID).toBeDefined(),expect(y).toBeDefined()}),it("should have a randomFillSync()",()=>{expect(globalThis.crypto.randomFillSync).toBeDefined(),expect(u).toBeDefined()}),it("should have a randomFill()",()=>{expect(globalThis.crypto.randomFill).toBeDefined(),expect(i).toBeDefined()}),it("should have a webcrypto and should be equal to globalThis.crypto",()=>{expect(r).toBeDefined(),expect(r===globalThis.crypto).toBeTruthy(),expect(r).toStrictEqual(globalThis.crypto)})});describe("Hashing",()=>{it("should hash to sha256 with b64 encoding",()=>{let e=s("sha256").update("message").digest("base64");expect(e).toEqual("q1MKE+RZFJgrefm34/uplM/R8/si9xzqGvvwK0YMbR0=")}),it("should hash to sha256 with hex encoding",()=>{let e=s("sha256").update("message").digest("hex");expect(e).toEqual("ab530a13e45914982b79f9b7e3fba994cfd1f3fb22f71cea1afbf02b460c6d1d")}),it("should hash to hmac-sha256 with b64 encoding",()=>{let e=c("sha256","key").update("message").digest("base64");expect(e).toEqual("bp7ym3X//Ft6uuUn1Y/a2y/kLnIZARl2kXNDBl9Y7Uo=")}),it("should hash to hmac-sha256 with hex encoding",()=>{let e=c("sha256","key").update("message").digest("hex");expect(e).toEqual("6e9ef29b75fffc5b7abae527d58fdadb2fe42e7219011976917343065f58ed4a")})});describe("random",()=>{it("should generate a random buffer synchronously using randomFillSync",()=>{let e=u(Buffer.alloc(16));expect(e.length).toEqual(16)}),it("should generate a random buffer asynchronously using randomFill",e=>{i(Buffer.alloc(16),(t,a)=>{expect(t).toBeNull(),expect(a.length).toEqual(16),e()})}),it("should generate random bytes synchronously into a Uint8Array using randomFillSync",()=>{let e=new Uint8Array(16);u(e),expect(e.length).toEqual(16);for(let t of e)expect(t>=0&&t<=255).toBeTruthy()}),it("should generate random bytes asynchronously into a DataView using randomFill",e=>{let t=new DataView(new ArrayBuffer(32));i(t,(a,f)=>{expect(a).toBeNull(),expect(f.buffer).toEqual(t.buffer),expect(t.byteLength).toEqual(32);for(let n=0;n<32;n++)expect(t.getUint8(n)>=0&&t.getUint8(n)<=255).toBeTruthy();e()})}),it("should generate a random UUID using randomUUID",()=>{let e=y();expect(e.length).toEqual(36);let t=/^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/;expect(e).toMatch(t)}),it("should generate a random bytes buffer using randomBytes",()=>{let e=h(16);expect(e).toBeInstanceOf(Buffer),expect(e.length).toEqual(16)}),it("should generate a random int using randomInt",()=>{for(let e of[...Array(10).keys()]){let t=l(Number.MAX_SAFE_INTEGER-1,Number.MAX_SAFE_INTEGER);expect(typeof t).toEqual("number"),expect(Number.MAX_SAFE_INTEGER-1).toEqual(t),expect(typeof t).toEqual("number")}for(let e of[...Array(20).keys()]){let t=l(0,5);expect(t).toBeLessThan(5),expect(t).toBeGreaterThanOrEqual(0)}}),it("should generate random bytes synchronously into a Int8Array using getRandomValues",()=>{let e=new Int8Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=-128&&t<=127).toBeTruthy()}),it("should generate random bytes synchronously into a Uint8Array using getRandomValues",()=>{let e=new Uint8Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=0&&t<=255).toBeTruthy()}),it("should generate random bytes synchronously into a Uint8ClampedArray using getRandomValues",()=>{let e=new Uint8ClampedArray(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=0&&t<=255).toBeTruthy()}),it("should generate random bytes synchronously into a Int16Array using getRandomValues",()=>{let e=new Int16Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=-32768&&t<=32767).toBeTruthy()}),it("should generate random bytes synchronously into a Uint16Array using getRandomValues",()=>{let e=new Uint16Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=0&&t<=65535).toBeTruthy()}),it("should generate random bytes synchronously into a Int32Array using getRandomValues",()=>{let e=new Int32Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=-2147483648&&t<=2147483647).toBeTruthy()}),it("should generate random bytes synchronously into a Uint32Array using getRandomValues",()=>{let e=new Uint32Array(10);o(e),expect(e.length).toEqual(10);for(let t of e)expect(t>=0&&t<=4294967295).toBeTruthy()}),it("should be an error, if it exceeds 65536 bytes",()=>{let e=new BigInt64Array(8193),t="";try{o(e)}catch(a){t=a.message}expect(t).toEqual("QuotaExceededError: The requested length exceeds 65,536 bytes")})});
